  render: () => {
    return <Combobox>
        <ComboboxInput placeholder="Search framework..." />
        <ComboboxContent>
          <ComboboxList>
            <ComboboxEmpty>No framework found.</ComboboxEmpty>
            {frameworks.map(framework => <ComboboxItem key={framework.value} value={framework.value}>
                {framework.label}
              </ComboboxItem>)}
          </ComboboxList>
        </ComboboxContent>
      </Combobox>;
  }
